@@ -669,9 +669,23 @@ pub fn genIter(self: *NativeCodegen, args: []ast.Node) CodegenError!void {

     // For tuples/arrays/slices, create a proper SequenceIterator
     if (arg_type == .tuple or arg_type == .list) {
-        try self.emit("runtime.iterators.iter(i64, ");
-        try self.genExpr(args[0]);
-        try self.emit(")");
+        // Check if this is an ArrayList variable (needs .items accessor)
+        const is_arraylist = if (args[0] == .name)
+            self.isArrayListVar(args[0].name.id)
+        else
+            false;
+
+        if (is_arraylist) {
+            // ArrayList variable: use .items to get slice
+            try self.emit("runtime.iterators.iter(i64, ");
+            try self.genExpr(args[0]);
+            try self.emit(".items)");
+        } else {
+            // Use runtime check to handle both ArrayList and fixed array
+            try self.emit("iter_list_blk: { const __iterable = ");
+            try self.genExpr(args[0]);
+            try self.emit("; break :iter_list_blk runtime.iterators.iter(i64, if (@hasField(@TypeOf(__iterable), \"items\")) __iterable.items else __iterable); }");
+        }
         return;
     }

@@ -479,17 +479,20 @@ pub fn genSubscript(self: *NativeCodegen, subscript: ast.Node.Subscript) Codegen
                             }
                             try self.emitFmt("; if (__idx >= __arr.items.len) return error.IndexError; break :arr_{d} __arr.items[__idx]; }}", .{label_id});
                         } else {
-                            // Array/slice: direct indexing (Zig provides safety in debug mode)
+                            // Unknown type: use runtime @hasField check to handle ArrayList vs array
+                            const label_id = self.block_label_counter;
+                            self.block_label_counter += 1;
+                            try self.emitFmt("arr_{d}: {{ const __s = ", .{label_id});
                             try genExpr(self, subscript.value.*);
-                            try self.emit("[");
+                            try self.emit("; const __idx = ");
                             if (needs_cast) {
                                 try self.emit("@as(usize, @intCast(");
                             }
                             try genExpr(self, subscript.slice.index.*);
                             if (needs_cast) {
                                 try self.emit("))");
                             }
-                            try self.emit("]");
+                            try self.emitFmt("; break :arr_{d} if (@hasField(@TypeOf(__s), \"items\")) __s.items[__idx] else __s[__idx]; }}", .{label_id});
                         }
                     }
                 }
